msg.topic = `
CREATE TABLE IF NOT EXISTS users (
    uid        TEXT PRIMARY KEY,
    name       TEXT NOT NULL,
    schedule   TEXT DEFAULT NULL,
    expires_at TEXT DEFAULT NULL,
    enabled    INTEGER NOT NULL DEFAULT 1,
    created_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now')),
    updated_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now'))
);
CREATE TABLE IF NOT EXISTS audit (
    id         INTEGER PRIMARY KEY AUTOINCREMENT,
    ts         TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now')),
    actor      TEXT NOT NULL,
    action     TEXT NOT NULL,
    target_uid TEXT,
    details    TEXT
);
CREATE INDEX IF NOT EXISTS idx_audit_ts  ON audit(ts DESC);
CREATE INDEX IF NOT EXISTS idx_audit_uid ON audit(target_uid);
`;
return msg;

const parts = msg.topic.split('/');
const deviceId = parts[1];
const {uid, req_id} = msg.payload;
if (!uid || !req_id) { node.warn('Request malformado: ' + JSON.stringify(msg.payload)); return null; }
msg.deviceId = deviceId;
msg.uid = uid.toUpperCase();
msg.req_id = req_id;
const esc = s => String(s||'').replace(/'/g, "''");
msg.topic = "SELECT uid, name, schedule, expires_at, enabled FROM users WHERE uid = '" + esc(msg.uid) + "'";
return msg;

const lockdown   = flow.get('lockdown') || false;
const defaultTtl = flow.get('cache_ttl_s') || 86400;
const {uid, deviceId, req_id} = msg;
const rows = msg.payload;

let allowed = false;
let reason  = '';
let ttl     = defaultTtl;

if (lockdown) {
    reason = 'lockdown';
} else if (!rows || rows.length === 0) {
    reason = 'user_not_found';
} else {
    const u = rows[0];
    if (!u.enabled) {
        reason = 'disabled';
    } else if (u.expires_at && new Date(u.expires_at) < new Date()) {
        reason = 'expired';
    } else if (u.schedule) {
        const sched = JSON.parse(u.schedule);
        const now = new Date();
        const day = now.getDay();
        const hhmm = now.getHours() * 60 + now.getMinutes();
        const [fH, fM] = sched.from.split(':').map(Number);
        const [tH, tM] = sched.to.split(':').map(Number);
        const fromMin = fH * 60 + fM;
        const toMin   = tH * 60 + tM;
        if (!sched.days.includes(day) || hhmm < fromMin || hhmm >= toMin) {
            reason = 'out_of_schedule';
        } else {
            allowed = true;
            ttl = Math.min(defaultTtl, (toMin - hhmm) * 60);
        }
    } else {
        allowed = true;
        if (u.expires_at) {
            ttl = Math.min(defaultTtl, Math.floor((new Date(u.expires_at) - new Date()) / 1000));
        }
    }
}

const response = {req_id, uid, allowed};
if (allowed) response.ttl = ttl;

node.log(`[${deviceId}] UID=${uid} allowed=${allowed} reason=${reason || 'ok'}`);
msg.topic   = `access/${deviceId}/response`;
msg.payload = response;
msg.qos     = 1;
msg.retain  = false;
return msg;

const parts = msg.topic.split('/');
const deviceId = parts[1];
const {uid, outcome, source, ts} = msg.payload;
if (!uid || !outcome) { node.warn('Evento malformado: ' + JSON.stringify(msg.payload)); return [null,null,null]; }
msg.deviceId = deviceId;
msg.uid      = uid.toUpperCase();
msg.outcome  = outcome;
msg.source   = source || 'unknown';
msg.eventTs  = ts || new Date().toISOString();
// Salida 0: InfluxDB, Salida 1: SQLite audit, Salida 2: alerta denied
return [msg, msg, outcome === 'denied' ? msg : null];

// Format: [fields, tags] — measurement is set on the influxdb out node
msg.payload = [
    { uid: msg.uid, count: 1 },
    { device_id: msg.deviceId, outcome: msg.outcome, source: msg.source }
];
return msg;

const esc = s => String(s||'').replace(/'/g, "''");
const details = JSON.stringify({source: msg.source, ts: msg.eventTs});
msg.topic = "INSERT INTO audit (actor, action, target_uid, details) VALUES ('" + esc(msg.deviceId) + "', 'access_" + esc(msg.outcome) + "', '" + esc(msg.uid) + "', '" + esc(details) + "')";
return msg;

const ids = (env.get('TELEGRAM_ADMIN_IDS') || '').split(',').map(s => s.trim()).filter(Boolean);
if (!ids.length) return null;
msg.payload = {
    chatId:  parseInt(ids[0]),
    type:    'message',
    content: `⛔ Acceso DENEGADO\nDispositivo: ${msg.deviceId}\nUID: ${msg.uid}\nMotivo: ${msg.source}\nHora: ${msg.eventTs}`
};
return msg;

const deviceId = msg.topic.split('/')[1];
const {online} = msg.payload;
if (online !== false) return null;
const ids = (env.get('TELEGRAM_ADMIN_IDS') || '').split(',').map(s => s.trim()).filter(Boolean);
if (!ids.length) return null;
msg.payload = {
    chatId:  parseInt(ids[0]),
    type:    'message',
    content: `🔴 DISPOSITIVO OFFLINE\nID: ${deviceId}\nHora: ${new Date().toISOString()}`
};
return msg;

const ids = (env.get('TELEGRAM_ADMIN_IDS') || '').split(',').map(s => s.trim());
const chatId = String(msg.payload.chatId);
if (!ids.includes(chatId)) {
    node.warn('No autorizado chatId: ' + chatId);
    node.send([null, {payload:{chatId:msg.payload.chatId,type:'message',content:'⛔ No autorizado.'}}]);
    return null;
}
return [msg, null];

const text = (msg.payload.content || '').trim();
const parts = text.split(/\s+/);
msg._cmd    = parts[0].toLowerCase();
msg._parts  = parts;
msg._chatId = msg.payload.chatId;
msg._actor  = (msg.payload.from && msg.payload.from.username) ? msg.payload.from.username : String(msg.payload.chatId);
return msg;

const routes = {'/alta':0,'/baja':1,'/habilitar':2,'/deshabilitar':3,'/horario':4,'/expira':5,'/usuario':6,'/ultimos':7,'/lockdown':8,'/ttl':9,'/ayuda':10,'/usuarios':11};
const idx = routes[msg._cmd];
if (idx === undefined) {
    node.send(Array(13).fill(null).map((_,i) => i===12 ? {payload:{chatId:msg._chatId,type:'message',content:'Comando desconocido. Usá /ayuda.'}} : null));
    return null;
}
const out = Array(13).fill(null);
out[idx] = msg;
return out;

const [,uid,...rest] = msg._parts;
if (!uid || !rest.length) { node.send([null,{payload:{chatId:msg._chatId,type:'message',content:'Uso: /alta <uid> <nombre>'}}]); return null; }
const name = rest.join(' ');
const esc = s => String(s||'').replace(/'/g, "''");
msg._uid = uid.toUpperCase(); msg._name = name; msg._action = 'create'; msg._details = JSON.stringify({name});
msg.topic = "INSERT INTO users (uid, name) VALUES ('" + esc(msg._uid) + "', '" + esc(name) + "') ON CONFLICT(uid) DO UPDATE SET name=excluded.name, enabled=1, updated_at=strftime('%Y-%m-%dT%H:%M:%SZ','now')";
return [msg, null];

const [,uid] = msg._parts;
if (!uid) { node.send([null,{payload:{chatId:msg._chatId,type:'message',content:'Uso: /baja <uid>'}}]); return null; }
const esc = s => String(s||'').replace(/'/g, "''");
msg._uid = uid.toUpperCase(); msg._action = 'disable'; msg._details = null;
msg.topic = "UPDATE users SET enabled=0, updated_at=strftime('%Y-%m-%dT%H:%M:%SZ','now') WHERE uid='" + esc(msg._uid) + "'";
return [msg, null];

const [,uid] = msg._parts;
if (!uid) { node.send([null,{payload:{chatId:msg._chatId,type:'message',content:'Uso: /habilitar <uid>'}}]); return null; }
const esc = s => String(s||'').replace(/'/g, "''");
msg._uid = uid.toUpperCase(); msg._action = 'enable'; msg._details = null;
msg.topic = "UPDATE users SET enabled=1, updated_at=strftime('%Y-%m-%dT%H:%M:%SZ','now') WHERE uid='" + esc(msg._uid) + "'";
return [msg, null];

const [,uid] = msg._parts;
if (!uid) { node.send([null,{payload:{chatId:msg._chatId,type:'message',content:'Uso: /deshabilitar <uid>'}}]); return null; }
const esc = s => String(s||'').replace(/'/g, "''");
msg._uid = uid.toUpperCase(); msg._action = 'disable'; msg._details = null;
msg.topic = "UPDATE users SET enabled=0, updated_at=strftime('%Y-%m-%dT%H:%M:%SZ','now') WHERE uid='" + esc(msg._uid) + "'";
return [msg, null];

// /horario <uid> <dias_csv> <HH:MM> <HH:MM>
const [,uid,diasStr,desde,hasta] = msg._parts;
if (!uid||!diasStr||!desde||!hasta) { node.send([null,{payload:{chatId:msg._chatId,type:'message',content:'Uso: /horario <uid> <dias_csv> <HH:MM> <HH:MM>\nEj: /horario AABB1234 1,2,3,4,5 08:00 18:00'}}]); return null; }
const schedule = JSON.stringify({days: diasStr.split(',').map(Number), from: desde, to: hasta});
const esc = s => String(s||'').replace(/'/g, "''");
msg._uid = uid.toUpperCase(); msg._action = 'set_schedule'; msg._details = schedule;
msg.topic = "UPDATE users SET schedule='" + esc(schedule) + "', updated_at=strftime('%Y-%m-%dT%H:%M:%SZ','now') WHERE uid='" + esc(msg._uid) + "'";
return [msg, null];

// /expira <uid> <ISO8601|none>
const [,uid,fecha] = msg._parts;
if (!uid||!fecha) { node.send([null,{payload:{chatId:msg._chatId,type:'message',content:'Uso: /expira <uid> <ISO8601|none>'}}]); return null; }
const expiresAt = fecha.toLowerCase()==='none' ? null : fecha;
const esc = s => String(s||'').replace(/'/g, "''");
msg._uid = uid.toUpperCase(); msg._action = 'set_expiry'; msg._details = JSON.stringify({expires_at: expiresAt});
const expiresVal = expiresAt === null ? 'NULL' : "'" + esc(expiresAt) + "'";
msg.topic = "UPDATE users SET expires_at=" + expiresVal + ", updated_at=strftime('%Y-%m-%dT%H:%M:%SZ','now') WHERE uid='" + esc(msg._uid) + "'";
return [msg, null];

const {_uid:uid, _action:action, _actor:actor, _details:details, _chatId:chatId, _name:name} = msg;
const esc = s => String(s||'').replace(/'/g, "''");

// 1) Audit
const am = {topic:"INSERT INTO audit (actor,action,target_uid,details) VALUES ('" + esc(actor) + "','" + esc(action) + "','" + esc(uid) + "','" + esc(details) + "')"};
// 2) Invalidar cache en ESP32
const im = {topic:'access/door01/command/invalidate', payload:JSON.stringify({uid}), qos:1, retain:false};
// 3) Reply Telegram
const icons = {create:'✅',enable:'✅',disable:'❌',set_schedule:'📅',set_expiry:'⏱️'};
const icon  = icons[action] || 'ℹ️';
const label = name ? ` (${name})` : '';
const rm = {payload:{chatId, type:'message', content:`${icon} \`${action}\` aplicado sobre UID \`${uid}\`${label}.`, options:{parse_mode:'Markdown'}}};

node.send([am, im, rm]);
return null;

const [,uid] = msg._parts;
if (!uid) { node.send([{payload:{chatId:msg._chatId,type:'message',content:'Uso: /usuario <uid>'}}]); return null; }
const esc = s => String(s||'').replace(/'/g, "''");
msg.topic = "SELECT uid,name,schedule,expires_at,enabled,created_at FROM users WHERE uid='" + esc(uid.toUpperCase()) + "'";
return msg;

const rows = msg.payload;
let text;
if (!rows||!rows.length) {
    text = '❌ Usuario no encontrado.';
} else {
    const u = rows[0];
    text = `👤 *Usuario*\nUID: \`${u.uid}\`\nNombre: ${u.name}\nEstado: ${u.enabled?'✅ Habilitado':'❌ Deshabilitado'}\nHorario: ${u.schedule||'Sin restricción'}\nExpira: ${u.expires_at||'No expira'}\nAlta: ${u.created_at}`;
}
msg.payload = {chatId:msg._chatId, type:'message', content:text, options:{parse_mode:'Markdown'}};
return msg;

const n = Math.min(parseInt(msg._parts[1])||10, 50);
msg.topic = `SELECT a.ts, a.target_uid, a.action, a.actor, u.name FROM audit a LEFT JOIN users u ON u.uid = a.target_uid WHERE a.action LIKE 'access_%' ORDER BY a.ts DESC LIMIT ${n}`;
return msg;

const rows = msg.payload;
if (!rows||!rows.length) {
    msg.payload = {chatId:msg._chatId, type:'message', content:'No hay eventos registrados.'};
} else {
    const lines = rows.map(r => {
        const ok = r.action.replace('access_','') === 'granted';
        const who = r.name ? `${r.name} (${r.target_uid})` : (r.target_uid || 'desconocido');
        return `${ok?'✅':'❌'} ${r.ts.slice(0,19)} | ${who} | ${r.actor}`;
    });
    msg.payload = {chatId:msg._chatId, type:'message', content:`*Últimos ${rows.length} eventos:*\n\`\`\`\n${lines.join('\n')}\n\`\`\``, options:{parse_mode:'Markdown'}};
}
return msg;

const [,state] = msg._parts;
if (state!=='on'&&state!=='off') { node.send([null,null,{payload:{chatId:msg._chatId,type:'message',content:'Uso: /lockdown on|off'}}]); return null; }
const enabled = state==='on';
flow.set('lockdown', enabled);
const im = {topic:'access/door01/command/lockdown', payload:JSON.stringify({enabled}), qos:1, retain:true};
const am = {topic:"INSERT INTO audit (actor,action,target_uid,details) VALUES (?,?,NULL,NULL)", params:[msg._actor, enabled?'lockdown_on':'lockdown_off']};
const rm = {payload:{chatId:msg._chatId, type:'message', content:`${enabled?'🔒 LOCKDOWN ACTIVADO — todas las tarjetas serán denegadas.':'🔓 Lockdown desactivado.'}`}};
node.send([im, am, rm]);
return null;

const secs = parseInt(msg._parts[1]);
if (!secs||secs<60||secs>2592000) { node.send([null,null,{payload:{chatId:msg._chatId,type:'message',content:'Uso: /ttl <segundos> (60 a 2592000)'}}]); return null; }
flow.set('cache_ttl_s', secs);
const im = {topic:'access/door01/command/config', payload:JSON.stringify({cache_ttl_s:secs}), qos:1, retain:false};
const am = {topic:"INSERT INTO audit (actor,action,target_uid,details) VALUES (?,?,NULL,?)", params:[msg._actor,'set_ttl',JSON.stringify({ttl:secs})]};
const rm = {payload:{chatId:msg._chatId, type:'message', content:`⚙️ TTL actualizado a ${secs}s (${(secs/3600).toFixed(1)}h).`}};
node.send([im, am, rm]);
return null;

const rows = msg.payload;
if (!rows||!rows.length) {
    msg.payload = {chatId:msg._chatId, type:'message', content:'No hay usuarios registrados.'};
} else {
    const lines = rows.map(r => {
        const estado = r.enabled ? '✅' : '❌';
        const expira = r.expires_at ? ` | exp: ${r.expires_at.slice(0,10)}` : '';
        const horario = r.schedule ? ' | 🕐' : '';
        return `${estado} ${r.name} — \`${r.uid}\`${expira}${horario}`;
    });
    msg.payload = {chatId:msg._chatId, type:'message', content:`👥 *Usuarios registrados (${rows.length}):*\n${lines.join('\n')}`, options:{parse_mode:'Markdown'}};
}
return msg;
